### Run a published workflow
POST {{host}}/v1/workflows/{{id}}
Authorization: Bearer {{token}}
X-Runway-Version: 2024-11-06
Content-Type: application/json
Accept: application/json

{
  "nodeOutputs": {}
}

## Responses
# 200
# Description: The response from running a workflow.
# Content-Type: application/json
# 404
# Description: The published workflow does not exist or was deleted.
# Content-Type: application/json

using var client = new RunwayClient(apiKey);
var response = await client.Workflows.GetWorkflowsAsync();

